using System.Runtime.InteropServices;
using Flipit.Core;
using Flipit.Infrastructure;
using Microsoft.Extensions.Logging;

namespace Flipit.Clipboard;

/// <summary>
/// Clipboard access using Win32 APIs directly for reliability.
/// Uses retry logic because the clipboard can be temporarily locked.
/// </summary>
public sealed class ClipboardService : IClipboardService
{
    private readonly ILogger<ClipboardService> _logger;
    private const int MaxRetries = 5;
    private const int RetryDelayMs = 20;

    public ClipboardService(ILogger<ClipboardService> logger)
    {
        _logger = logger;
    }

    public uint GetSequenceNumber() => NativeMethods.GetClipboardSequenceNumber();

    public string? GetText()
    {
        for (int attempt = 1; attempt <= MaxRetries; attempt++)
        {
            try
            {
                if (!NativeMethods.OpenClipboard(IntPtr.Zero))
                {
                    Thread.Sleep(RetryDelayMs);
                    continue;
                }

                try
                {
                    var hData = NativeMethods.GetClipboardData(NativeMethods.CF_UNICODETEXT);
                    if (hData == IntPtr.Zero) return null;

                    var ptr = NativeMethods.GlobalLock(hData);
                    if (ptr == IntPtr.Zero) return null;

                    try
                    {
                        return Marshal.PtrToStringUni(ptr);
                    }
                    finally
                    {
                        NativeMethods.GlobalUnlock(hData);
                    }
                }
                finally
                {
                    NativeMethods.CloseClipboard();
                }
            }
            catch (Exception ex)
            {
                _logger.LogWarning(ex, "Clipboard read attempt {Attempt} failed", attempt);
                Thread.Sleep(RetryDelayMs);
            }
        }

        _logger.LogError("Failed to read clipboard after {MaxRetries} attempts", MaxRetries);
        return null;
    }

    public bool SetText(string text)
    {
        for (int attempt = 1; attempt <= MaxRetries; attempt++)
        {
            try
            {
                if (!NativeMethods.OpenClipboard(IntPtr.Zero))
                {
                    Thread.Sleep(RetryDelayMs);
                    continue;
                }

                try
                {
                    NativeMethods.EmptyClipboard();

                    // Allocate global memory for the Unicode string
                    var bytes = System.Text.Encoding.Unicode.GetByteCount(text) + 2; // +2 for null terminator
                    var hMem = NativeMethods.GlobalAlloc(NativeMethods.GMEM_MOVEABLE, (UIntPtr)bytes);
                    if (hMem == IntPtr.Zero) return false;

                    var ptr = NativeMethods.GlobalLock(hMem);
                    if (ptr == IntPtr.Zero)
                    {
                        NativeMethods.GlobalFree(hMem);
                        return false;
                    }

                    try
                    {
                        Marshal.Copy(System.Text.Encoding.Unicode.GetBytes(text + "\0"), 0, ptr, bytes);
                    }
                    finally
                    {
                        NativeMethods.GlobalUnlock(hMem);
                    }

                    var result = NativeMethods.SetClipboardData(NativeMethods.CF_UNICODETEXT, hMem);
                    if (result == IntPtr.Zero)
                    {
                        // SetClipboardData failed — we still own hMem, so free it
                        NativeMethods.GlobalFree(hMem);
                        return false;
                    }
                    // On success the clipboard owns hMem; do NOT free it
                    return true;
                }
                finally
                {
                    NativeMethods.CloseClipboard();
                }
            }
            catch (Exception ex)
            {
                _logger.LogWarning(ex, "Clipboard write attempt {Attempt} failed", attempt);
                Thread.Sleep(RetryDelayMs);
            }
        }

        _logger.LogError("Failed to write clipboard after {MaxRetries} attempts", MaxRetries);
        return false;
    }

    public bool Clear()
    {
        for (int attempt = 1; attempt <= MaxRetries; attempt++)
        {
            try
            {
                if (!NativeMethods.OpenClipboard(IntPtr.Zero))
                {
                    Thread.Sleep(RetryDelayMs);
                    continue;
                }
                try
                {
                    return NativeMethods.EmptyClipboard();
                }
                finally
                {
                    NativeMethods.CloseClipboard();
                }
            }
            catch (Exception ex)
            {
                _logger.LogWarning(ex, "Clipboard clear attempt {Attempt} failed", attempt);
                Thread.Sleep(RetryDelayMs);
            }
        }
        _logger.LogError("Failed to clear clipboard after {MaxRetries} attempts", MaxRetries);
        return false;
    }
}

using System.Runtime.InteropServices;
using Flipit.Core;
using Flipit.Infrastructure;
using Microsoft.Extensions.Logging;

namespace Flipit.Clipboard;

/// <summary>
/// Clipboard access using Win32 APIs directly for reliability.
/// Uses retry logic because the clipboard can be temporarily locked.
///
/// SECURITY NOTES:
/// - Clipboard content is NEVER logged.
/// - No sentinel or marker values are written to the clipboard.
/// - GlobalLock failures are logged as warnings (without the content).
/// </summary>
public sealed class ClipboardService : IClipboardService
{
    private readonly ILogger<ClipboardService> _logger;
    private const int MaxRetries   = 5;
    private const int RetryDelayMs = 20;

    public ClipboardService(ILogger<ClipboardService> logger)
    {
        _logger = logger;
    }

    public uint GetSequenceNumber() => NativeMethods.GetClipboardSequenceNumber();

    public string? GetText()
    {
        var result = RetryClipboard<string?>("read", () =>
        {
            if (!NativeMethods.OpenClipboard(IntPtr.Zero))
                return ClipboardResult<string?>.Locked();

            try
            {
                var hData = NativeMethods.GetClipboardData(NativeMethods.CF_UNICODETEXT);
                if (hData == IntPtr.Zero)
                    return ClipboardResult<string?>.Success(null); // no text on clipboard

                var ptr = NativeMethods.GlobalLock(hData);
                if (ptr == IntPtr.Zero)
                {
                    _logger.LogWarning(
                        "GlobalLock failed for clipboard handle — Win32 error {Error}",
                        Marshal.GetLastWin32Error());
                    return ClipboardResult<string?>.Success(null);
                }

                try   { return ClipboardResult<string?>.Success(Marshal.PtrToStringUni(ptr)); }
                finally { NativeMethods.GlobalUnlock(hData); }
            }
            finally
            {
                NativeMethods.CloseClipboard();
            }
        });

        return result.Value;
    }

    public bool SetText(string text)
    {
        var result = RetryClipboard<bool>("write", () =>
        {
            if (!NativeMethods.OpenClipboard(IntPtr.Zero))
                return ClipboardResult<bool>.Locked();

            try
            {
                NativeMethods.EmptyClipboard();

                // Allocate global memory for the Unicode string (including null terminator)
                var bytes = System.Text.Encoding.Unicode.GetByteCount(text) + 2;
                var hMem  = NativeMethods.GlobalAlloc(NativeMethods.GMEM_MOVEABLE, (UIntPtr)bytes);
                if (hMem == IntPtr.Zero)
                    return ClipboardResult<bool>.Success(false);

                var ptr = NativeMethods.GlobalLock(hMem);
                if (ptr == IntPtr.Zero)
                {
                    NativeMethods.GlobalFree(hMem);
                    return ClipboardResult<bool>.Success(false);
                }

                try
                {
                    Marshal.Copy(System.Text.Encoding.Unicode.GetBytes(text + "\0"), 0, ptr, bytes);
                }
                finally
                {
                    NativeMethods.GlobalUnlock(hMem);
                }

                var handle = NativeMethods.SetClipboardData(NativeMethods.CF_UNICODETEXT, hMem);
                if (handle == IntPtr.Zero)
                {
                    // SetClipboardData failed — we still own hMem, so free it
                    NativeMethods.GlobalFree(hMem);
                    return ClipboardResult<bool>.Success(false);
                }
                // On success the clipboard owns hMem; do NOT free it
                return ClipboardResult<bool>.Success(true);
            }
            finally
            {
                NativeMethods.CloseClipboard();
            }
        });

        return result.Value;
    }

    public bool Clear()
    {
        var result = RetryClipboard<bool>("clear", () =>
        {
            if (!NativeMethods.OpenClipboard(IntPtr.Zero))
                return ClipboardResult<bool>.Locked();

            try   { return ClipboardResult<bool>.Success(NativeMethods.EmptyClipboard()); }
            finally { NativeMethods.CloseClipboard(); }
        });

        return result.Value;
    }

    // ── Retry helper ─────────────────────────────────────────────────────────

    /// <summary>
    /// Retries a clipboard operation up to <see cref="MaxRetries"/> times.
    /// The operation returns <see cref="ClipboardResult{T}.Locked"/> to signal
    /// that <c>OpenClipboard</c> failed and the attempt should be retried.
    /// Any other result (including null values) is returned immediately.
    /// </summary>
    private ClipboardResult<T> RetryClipboard<T>(string operationName,
        Func<ClipboardResult<T>> operation)
    {
        for (int attempt = 1; attempt <= MaxRetries; attempt++)
        {
            try
            {
                var result = operation();
                if (!result.IsLocked) return result;

                // Clipboard was locked by another app — wait and retry
                Thread.Sleep(RetryDelayMs);
            }
            catch (Exception ex)
            {
                _logger.LogWarning(ex, "Clipboard {Operation} attempt {Attempt} failed",
                    operationName, attempt);
                Thread.Sleep(RetryDelayMs);
            }
        }

        _logger.LogError("Failed to {Operation} clipboard after {MaxRetries} attempts",
            operationName, MaxRetries);
        return ClipboardResult<T>.Success(default!);
    }

    // ── Result wrapper ────────────────────────────────────────────────────────

    private readonly record struct ClipboardResult<T>(bool IsLocked, T Value)
    {
        public static ClipboardResult<T> Locked()          => new(true,  default!);
        public static ClipboardResult<T> Success(T value)  => new(false, value);
    }
}

using Flipit.Core;
using Flipit.Infrastructure;
using Microsoft.Extensions.Logging;

namespace Flipit.Core;

/// <summary>
/// Orchestrates the full flip workflow using clipboard snapshots for
/// copy verification.  Never writes sentinel or marker values to the clipboard.
///
/// DETECTION STRATEGY:
///
///   Phase 1 — selection check (IsGenuineSelectionCopy):
///     Snapshot before Ctrl+C.  After Ctrl+C: seq must advance AND text must
///     differ from snapshot.  The text-diff step filters out Win11 Notepad /
///     Chromium apps that re-write the existing clipboard value on every Ctrl+C.
///
///   Scintilla fast-path (Notepad++, SciTE, …):
///     Notepad++ copies the ENTIRE CURRENT LINE on Ctrl+C even when nothing is
///     selected, which would fool Phase 1 into treating it as a genuine selection.
///     We query SCI_GETSELECTIONSTART / SCI_GETSELECTIONEND via SendMessage before
///     sending Ctrl+C.  If start == end (no real selection) we skip Phase 1 and
///     go directly to Phase 2 (line-select).
///
///   Phase 2 — line copy (WasWrittenAfter in LineSelector):
///     After Home→Shift+End, snapshot taken right before Ctrl+C.  Only seq
///     advancement is required (no text-diff) so that lines whose content equals
///     the previous clipboard text are still handled correctly.
///
/// RE-ENTRANCY:
///   SemaphoreSlim(1,1) drops a second hotkey press while a flip is in progress.
/// </summary>
public sealed class FlipOrchestrator : IFlipOrchestrator
{
    private readonly IKeyboardSimulator        _keyboard;
    private readonly IClipboardService         _clipboard;
    private readonly ITextConverter            _converter;
    private readonly ILineSelector             _lineSelector;
    private readonly IAppSettings              _settings;
    private readonly ILogger<FlipOrchestrator> _logger;

    private readonly SemaphoreSlim _gate = new(1, 1);

    private const int InitialSettleMs = 50;
    private const int AfterCopyMs     = 150;
    private const int BeforePasteMs   = 50;

    public FlipOrchestrator(
        IKeyboardSimulator keyboard,
        IClipboardService  clipboard,
        ITextConverter     converter,
        ILineSelector      lineSelector,
        IAppSettings       settings,
        ILogger<FlipOrchestrator> logger)
    {
        _keyboard     = keyboard;
        _clipboard    = clipboard;
        _converter    = converter;
        _lineSelector = lineSelector;
        _settings     = settings;
        _logger       = logger;
    }

    public async Task FlipAsync()
    {
        if (!_settings.IsEnabled) return;

        if (!_gate.Wait(0)) return;

        try   { await Task.Run(ExecuteFlip); }
        catch (Exception ex) { _logger.LogError(ex, "Unhandled exception in flip operation"); }
        finally { _gate.Release(); }
    }

    // ── Workflow ──────────────────────────────────────────────────────────────

    private void ExecuteFlip()
    {
        // Capture the focused child control before the settle delay.
        // Needed to detect Scintilla (Notepad++, SciTE, …) and apply the
        // correct selection strategy.
        var fgHwnd  = NativeMethods.GetForegroundWindow();
        var winInfo = WindowDiagnostics.Capture(fgHwnd);

        Thread.Sleep(InitialSettleMs);

        // ── Scintilla fast-path ───────────────────────────────────────────────
        // Notepad++ (Scintilla) copies the whole current line on Ctrl+C even
        // with no selection, making Phase 1 see a false SELECTION_FOUND.
        // Query the editor's own selection API to skip Phase 1 when appropriate.
        bool goDirectToLineSelect =
            winInfo.IsScintilla
            && winInfo.FocusedHandle != IntPtr.Zero
            && !ScintillaHasSelection(winInfo.FocusedHandle);

        string? textToConvert;

        if (!goDirectToLineSelect)
        {
            // ── Phase 1: detect existing text selection ───────────────────────
            var snapshot = new ClipboardSnapshot(
                _clipboard.GetSequenceNumber(),
                _clipboard.GetText());

            _keyboard.SendCopy();
            Thread.Sleep(AfterCopyMs);

            var seqAfter  = _clipboard.GetSequenceNumber();
            var textAfter = _clipboard.GetText();

            if (snapshot.IsGenuineSelectionCopy(seqAfter, textAfter))
            {
                textToConvert = textAfter;
            }
            else
            {
                textToConvert = RunLineSelect();
                if (textToConvert is null) return;
            }
        }
        else
        {
            // ── Phase 2 direct: Scintilla with no selection ───────────────────
            textToConvert = RunLineSelect();
            if (textToConvert is null) return;
        }

        // ── Phase 3: convert ──────────────────────────────────────────────────────
        var converted = _converter.Convert(textToConvert!);
        if (string.Equals(converted, textToConvert, StringComparison.Ordinal))
            return; // already the correct layout — nothing to do

        // ── Phase 4: paste ────────────────────────────────────────────────────
        if (!_clipboard.SetText(converted))
        {
            _logger.LogError("Failed to write converted text to clipboard — aborting paste");
            return;
        }

        Thread.Sleep(BeforePasteMs);
        _keyboard.SendPaste();
        Thread.Sleep(AfterCopyMs);
    }

    // ── Helpers ───────────────────────────────────────────────────────────────

    private string? RunLineSelect()
    {
        var text = _lineSelector.SelectAndCopy();

        if (text is null)
        {
            _logger.LogWarning("Line selection failed — aborting");
            return null;
        }

        if (string.IsNullOrEmpty(text))
            return null; // empty line — nothing to convert

        return text;
    }

    /// <summary>
    /// Returns true when the Scintilla control has a non-empty text selection.
    /// Queries SCI_GETSELECTIONSTART and SCI_GETSELECTIONEND via SendMessage.
    /// </summary>
    private static bool ScintillaHasSelection(IntPtr scintillaHwnd)
    {
        var start = NativeMethods.SendMessage(scintillaHwnd, NativeMethods.SCI_GETSELECTIONSTART, IntPtr.Zero, IntPtr.Zero).ToInt64();
        var end   = NativeMethods.SendMessage(scintillaHwnd, NativeMethods.SCI_GETSELECTIONEND,   IntPtr.Zero, IntPtr.Zero).ToInt64();
        return end > start;
    }
}

using Flipit.Core;
using Flipit.Infrastructure;
using Microsoft.Extensions.Logging;

namespace Flipit.Core;

/// <summary>
/// Orchestrates the full flip workflow using clipboard snapshots for
/// copy verification.  Never writes sentinel or marker values to the clipboard.
///
/// DETECTION STRATEGY:
///   Phase 1 — selection check (IsGenuineSelectionCopy)
///   Scintilla fast-path (Notepad++, SciTE, …)
///   Phase 2 — line copy (WasWrittenAfter in LineSelector)
///
/// SAFETY:
///   - The original clipboard content (text) is restored after the paste so the
///     user's clipboard is not permanently overwritten.
///   - HWND validity is re-checked after the initial settle delay to guard against
///     the TOCTOU race where a window is destroyed and its handle recycled.
///
/// RE-ENTRANCY:
///   SemaphoreSlim(1,1) drops a second hotkey press while a flip is in progress.
/// </summary>
public sealed class FlipOrchestrator : IFlipOrchestrator
{
    private readonly IKeyboardSimulator        _keyboard;
    private readonly IClipboardService         _clipboard;
    private readonly ITextConverter            _converter;
    private readonly ILineSelector             _lineSelector;
    private readonly IAppSettings              _settings;
    private readonly ILogger<FlipOrchestrator> _logger;

    private readonly SemaphoreSlim _gate = new(1, 1);

    private const int InitialSettleMs  = 50;
    private const int AfterCopyMs      = 150;
    private const int BeforePasteMs    = 50;
    private const int AfterPasteMs     = 150;
    private const int ClipboardRestoreDelayMs = 80;

    public FlipOrchestrator(
        IKeyboardSimulator keyboard,
        IClipboardService  clipboard,
        ITextConverter     converter,
        ILineSelector      lineSelector,
        IAppSettings       settings,
        ILogger<FlipOrchestrator> logger)
    {
        _keyboard     = keyboard;
        _clipboard    = clipboard;
        _converter    = converter;
        _lineSelector = lineSelector;
        _settings     = settings;
        _logger       = logger;
    }

    public async Task FlipAsync(CancellationToken ct = default)
    {
        if (!_settings.IsEnabled) return;

        if (!_gate.Wait(0))
        {
            _logger.LogDebug("Flip already in progress — dropping re-entrant request");
            return;
        }

        try
        {
            // TaskCreationOptions.LongRunning allocates a dedicated OS thread.
            // The flip worker holds the thread for up to ~600 ms (multiple sleeps);
            // using a pool thread for that long would starve the thread pool.
            await Task.Factory.StartNew(
                () => ExecuteFlip(ct),
                ct,
                TaskCreationOptions.LongRunning,
                TaskScheduler.Default);
        }
        catch (OperationCanceledException)
        {
            _logger.LogDebug("Flip cancelled");
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Unhandled exception in flip operation");
        }
        finally
        {
            _gate.Release();
        }
    }

    // ── Workflow ──────────────────────────────────────────────────────────────

    private void ExecuteFlip(CancellationToken ct)
    {
        // Capture the foreground window and its process ID BEFORE the settle delay.
        var fgHwnd = NativeMethods.GetForegroundWindow();
        NativeMethods.GetWindowThreadProcessId(fgHwnd, out uint originalPid);

        Thread.Sleep(InitialSettleMs);
        ct.ThrowIfCancellationRequested();

        // ── HWND validity check ───────────────────────────────────────────────
        // After the settle delay, verify the foreground window is still the same
        // process. The handle could be recycled to a different window/process if
        // the original window was destroyed during the delay.
        var fgHwndNow = NativeMethods.GetForegroundWindow();
        NativeMethods.GetWindowThreadProcessId(fgHwndNow, out uint currentPid);

        if (fgHwndNow == IntPtr.Zero || currentPid != originalPid)
        {
            _logger.LogWarning("Foreground window changed during settle delay — aborting flip");
            return;
        }

        // Re-capture window info after validity check so Scintilla detection
        // uses a fresh snapshot with the confirmed HWND.
        var winInfo = WindowDiagnostics.Capture(fgHwndNow);

        // ── Scintilla fast-path ───────────────────────────────────────────────
        // Notepad++ (Scintilla) copies the whole current line on Ctrl+C even
        // with no selection, making Phase 1 see a false SELECTION_FOUND.
        bool goDirectToLineSelect =
            winInfo.IsScintilla
            && winInfo.FocusedHandle != IntPtr.Zero
            && !ScintillaHasSelection(winInfo.FocusedHandle);

        // Save the original clipboard text so we can restore it after the paste.
        // This prevents the converted text from permanently replacing the
        // user's clipboard content.
        string? originalClipboard = _clipboard.GetText();

        string? textToConvert;

        if (!goDirectToLineSelect)
        {
            // ── Phase 1: detect existing text selection ───────────────────────
            var snapshot = new ClipboardSnapshot(
                _clipboard.GetSequenceNumber(),
                _clipboard.GetText());

            _keyboard.SendCopy();
            Thread.Sleep(AfterCopyMs);
            ct.ThrowIfCancellationRequested();

            var seqAfter  = _clipboard.GetSequenceNumber();
            var textAfter = _clipboard.GetText();

            if (snapshot.IsGenuineSelectionCopy(seqAfter, textAfter))
            {
                textToConvert = textAfter;
            }
            else
            {
                textToConvert = RunLineSelect(ct);
                if (textToConvert is null) return;
            }
        }
        else
        {
            // ── Phase 2 direct: Scintilla with no selection ───────────────────
            textToConvert = RunLineSelect(ct);
            if (textToConvert is null) return;
        }

        // ── Phase 3: convert ──────────────────────────────────────────────────
        var converted = _converter.Convert(textToConvert!);
        if (string.Equals(converted, textToConvert, StringComparison.Ordinal))
            return; // already the correct layout — nothing to do

        // ── Phase 4: paste ────────────────────────────────────────────────────
        if (!_clipboard.SetText(converted))
        {
            _logger.LogError("Failed to write converted text to clipboard — aborting paste");
            return;
        }

        Thread.Sleep(BeforePasteMs);
        _keyboard.SendPaste();
        Thread.Sleep(AfterPasteMs);
        ct.ThrowIfCancellationRequested();

        // ── Phase 5: restore original clipboard ──────────────────────────────
        // Restore pre-flip clipboard text so the user's clipboard is not
        // permanently replaced with the converted text.
        Thread.Sleep(ClipboardRestoreDelayMs);
        if (originalClipboard is not null)
        {
            if (!_clipboard.SetText(originalClipboard))
                _logger.LogWarning("Could not restore original clipboard content after flip");
        }
        else
        {
            // Original clipboard was empty or non-text — clear the converted text
            _clipboard.Clear();
        }
    }

    // ── Helpers ───────────────────────────────────────────────────────────────

    private string? RunLineSelect(CancellationToken ct)
    {
        ct.ThrowIfCancellationRequested();
        var text = _lineSelector.SelectAndCopy();

        if (text is null)
        {
            _logger.LogWarning("Line selection failed — aborting");
            return null;
        }

        if (string.IsNullOrEmpty(text))
            return null; // empty line — nothing to convert

        return text;
    }

    /// <summary>
    /// Returns true when the Scintilla control has a non-empty text selection.
    /// Queries SCI_GETSELECTIONSTART and SCI_GETSELECTIONEND via SendMessage.
    /// </summary>
    private static bool ScintillaHasSelection(IntPtr scintillaHwnd)
    {
        var start = NativeMethods.SendMessage(scintillaHwnd, NativeMethods.SCI_GETSELECTIONSTART, IntPtr.Zero, IntPtr.Zero).ToInt64();
        var end   = NativeMethods.SendMessage(scintillaHwnd, NativeMethods.SCI_GETSELECTIONEND,   IntPtr.Zero, IntPtr.Zero).ToInt64();
        return end > start;
    }
}

namespace Flipit.Core;

/// <summary>
/// Immutable value type describing a global hotkey: a virtual key plus optional modifiers.
/// </summary>
/// <param name="Key">The main virtual key (e.g. <see cref="Keys.F1"/>).</param>
/// <param name="Modifiers">Bitwise combination of modifier keys (Ctrl, Alt, Shift). Use <see cref="Keys.None"/> for no modifiers.</param>
public record HotkeyDefinition(Keys Key, Keys Modifiers = Keys.None)
{
    /// <summary>Default hotkey: F1 with no modifiers.</summary>
    public static readonly HotkeyDefinition Default = new(Keys.F1);

    /// <summary>
    /// Returns a human-readable string, e.g. "Ctrl+F6" or "F1".
    /// </summary>
    public string DisplayText
    {
        get
        {
            var parts = new List<string>();
            if (Modifiers.HasFlag(Keys.Control)) parts.Add("Ctrl");
            if (Modifiers.HasFlag(Keys.Alt))     parts.Add("Alt");
            if (Modifiers.HasFlag(Keys.Shift))   parts.Add("Shift");
            parts.Add(KeyDisplayName(Key));
            return string.Join("+", parts);
        }
    }

    /// <summary>
    /// Converts <see cref="Modifiers"/> to the bitmask expected by Win32 <c>RegisterHotKey</c>.
    /// </summary>
    public uint Win32Modifiers
    {
        get
        {
            uint m = 0;
            if (Modifiers.HasFlag(Keys.Alt))     m |= 0x0001; // MOD_ALT
            if (Modifiers.HasFlag(Keys.Control)) m |= 0x0002; // MOD_CONTROL
            if (Modifiers.HasFlag(Keys.Shift))   m |= 0x0004; // MOD_SHIFT
            return m;
        }
    }

    /// <summary>Returns the virtual key code expected by Win32.</summary>
    public uint Win32VirtualKey => (uint)Key;

    // ── Persistence helpers ──────────────────────────────────────────────────

    /// <summary>Serialise to a compact string for storage, e.g. "0x70:0x0".</summary>
    public string Serialize() => $"{(int)Key}:{(int)Modifiers}";

    /// <summary>
    /// Parse a string previously produced by <see cref="Serialize"/>.
    /// Returns <see cref="Default"/> on failure.
    /// </summary>
    public static HotkeyDefinition Deserialize(string? value)
    {
        if (string.IsNullOrWhiteSpace(value)) return Default;
        var parts = value.Split(':');
        if (parts.Length == 2
            && int.TryParse(parts[0], out int vk)
            && int.TryParse(parts[1], out int mod))
        {
            return new HotkeyDefinition((Keys)vk, (Keys)mod);
        }
        return Default;
    }

    // ── Private helpers ──────────────────────────────────────────────────────

    private static string KeyDisplayName(Keys key) => key switch
    {
        Keys.F1         => "F1",
        Keys.F2         => "F2",
        Keys.F3         => "F3",
        Keys.F4         => "F4",
        Keys.F5         => "F5",
        Keys.F6         => "F6",
        Keys.F7         => "F7",
        Keys.F8         => "F8",
        Keys.F9         => "F9",
        Keys.F10        => "F10",
        Keys.F11        => "F11",
        Keys.F12        => "F12",
        Keys.Insert     => "Insert",
        Keys.Pause      => "Pause",
        Keys.Scroll     => "Scroll Lock",
        Keys.Home       => "Home",
        Keys.End        => "End",
        Keys.PageUp     => "Page Up",
        Keys.PageDown   => "Page Down",
        _               => key.ToString()
    };
}

namespace Flipit.Core;

/// <summary>
/// Immutable value type describing a global hotkey: a virtual key plus optional modifiers.
/// </summary>
/// <param name="Key">The main virtual key (e.g. <see cref="Keys.F1"/>).</param>
/// <param name="Modifiers">Bitwise combination of modifier keys (Ctrl, Alt, Shift). Use <see cref="Keys.None"/> for no modifiers.</param>
public record HotkeyDefinition(Keys Key, Keys Modifiers = Keys.None)
{
    /// <summary>Default hotkey: F1 (no modifiers).</summary>
    public static readonly HotkeyDefinition Default = new(Keys.F1);

    /// <summary>
    /// Returns a human-readable string, e.g. "Ctrl+F6" or "F1".
    /// </summary>
    public string DisplayText
    {
        get
        {
            var parts = new List<string>();
            if (Modifiers.HasFlag(Keys.Control)) parts.Add("Ctrl");
            if (Modifiers.HasFlag(Keys.Alt))     parts.Add("Alt");
            if (Modifiers.HasFlag(Keys.Shift))   parts.Add("Shift");
            parts.Add(KeyDisplayName(Key));
            return string.Join("+", parts);
        }
    }

    /// <summary>
    /// Converts <see cref="Modifiers"/> to the bitmask expected by Win32 <c>RegisterHotKey</c>.
    /// </summary>
    public uint Win32Modifiers
    {
        get
        {
            uint m = 0;
            if (Modifiers.HasFlag(Keys.Alt))     m |= 0x0001; // MOD_ALT
            if (Modifiers.HasFlag(Keys.Control)) m |= 0x0002; // MOD_CONTROL
            if (Modifiers.HasFlag(Keys.Shift))   m |= 0x0004; // MOD_SHIFT
            return m;
        }
    }

    /// <summary>Returns the virtual key code expected by Win32.</summary>
    public uint Win32VirtualKey => (uint)Key;

    // ── Persistence helpers ──────────────────────────────────────────────────

    /// <summary>Serialise to a compact string for storage, e.g. "0x70:0x0".</summary>
    public string Serialize() => $"{(int)Key}:{(int)Modifiers}";

    /// <summary>
    /// Parse a string previously produced by <see cref="Serialize"/>.
    /// Returns <see cref="Default"/> on failure or when the parsed key is not
    /// in the allowed set (guards against tampered registry values).
    /// </summary>
    public static HotkeyDefinition Deserialize(string? value)
    {
        if (string.IsNullOrWhiteSpace(value)) return Default;
        var parts = value.Split(':');
        if (parts.Length == 2
            && int.TryParse(parts[0], out int vk)
            && int.TryParse(parts[1], out int mod))
        {
            var key = (Keys)vk;
            // Validate key is in the allowed set — prevents a tampered HKCU value
            // from registering an arbitrary VK (e.g. VK_SPACE = 0x20).
            if (!IsAllowedKey(key)) return Default;
            var modifiers = (Keys)mod & (Keys.Control | Keys.Alt | Keys.Shift);
            return new HotkeyDefinition(key, modifiers);
        }
        return Default;
    }

    /// <summary>
    /// Returns true when <paramref name="key"/> is an acceptable hotkey main key.
    /// Mirrors <c>HotkeyValidator.AllowedKeys</c> — kept here to avoid a
    /// circular dependency between Core and Settings.
    /// </summary>
    private static bool IsAllowedKey(Keys key) =>
        key is Keys.F1  or Keys.F2  or Keys.F3  or Keys.F4
            or Keys.F5  or Keys.F6  or Keys.F7  or Keys.F8
            or Keys.F9  or Keys.F10 or Keys.F11 or Keys.F12
            or Keys.Insert or Keys.Pause or Keys.Scroll
            or Keys.Home or Keys.End or Keys.PageUp or Keys.PageDown;

    // ── Private helpers ──────────────────────────────────────────────────────

    private static string KeyDisplayName(Keys key) => key switch
    {
        Keys.F1         => "F1",
        Keys.F2         => "F2",
        Keys.F3         => "F3",
        Keys.F4         => "F4",
        Keys.F5         => "F5",
        Keys.F6         => "F6",
        Keys.F7         => "F7",
        Keys.F8         => "F8",
        Keys.F9         => "F9",
        Keys.F10        => "F10",
        Keys.F11        => "F11",
        Keys.F12        => "F12",
        Keys.Insert     => "Insert",
        Keys.Pause      => "Pause",
        Keys.Scroll     => "Scroll Lock",
        Keys.Home       => "Home",
        Keys.End        => "End",
        Keys.PageUp     => "Page Up",
        Keys.PageDown   => "Page Down",
        _               => key.ToString()
    };
}

namespace Flipit.Core;

/// <summary>
/// Manages the clipboard for read/write operations.
/// </summary>
public interface IClipboardService
{
    /// <summary>
    /// Returns the current clipboard sequence number.
    /// This OS counter increments on every clipboard write by any process.
    /// Compare before and after a Ctrl+C to know with certainty whether
    /// new content was copied — regardless of what the text content is.
    /// </summary>
    uint GetSequenceNumber();

    /// <summary>
    /// Returns the current clipboard text, or null if unavailable.
    /// </summary>
    string? GetText();

    /// <summary>
    /// Sets the clipboard text. Returns false on failure.
    /// </summary>
    bool SetText(string text);
}

