using System.Runtime.InteropServices;

namespace Flipit.Infrastructure;

/// <summary>
/// All Win32 P/Invoke declarations in one place.
/// </summary>
internal static class NativeMethods
{
    // ── Hotkey ───────────────────────────────────────────────────────────────

    [DllImport("user32.dll", SetLastError = true)]
    [return: MarshalAs(UnmanagedType.Bool)]
    internal static extern bool RegisterHotKey(IntPtr hWnd, int id, uint fsModifiers, uint vk);

    [DllImport("user32.dll", SetLastError = true)]
    [return: MarshalAs(UnmanagedType.Bool)]
    internal static extern bool UnregisterHotKey(IntPtr hWnd, int id);

    // ── SendInput ────────────────────────────────────────────────────────────

    [DllImport("user32.dll", SetLastError = true)]
    internal static extern uint SendInput(uint nInputs, INPUT[] pInputs, int cbSize);

    [StructLayout(LayoutKind.Sequential)]
    internal struct INPUT
    {
        internal uint type;
        internal InputUnion U;
    }

    [StructLayout(LayoutKind.Explicit)]
    internal struct InputUnion
    {
        [FieldOffset(0)] internal MOUSEINPUT mi;
        [FieldOffset(0)] internal KEYBDINPUT ki;
        [FieldOffset(0)] internal HARDWAREINPUT hi;
    }

    [StructLayout(LayoutKind.Sequential)]
    internal struct KEYBDINPUT
    {
        internal ushort wVk;
        internal ushort wScan;
        internal uint dwFlags;
        internal uint time;
        internal IntPtr dwExtraInfo;
    }

    [StructLayout(LayoutKind.Sequential)]
    internal struct MOUSEINPUT
    {
        internal int dx, dy, mouseData;
        internal uint dwFlags, time;
        internal IntPtr dwExtraInfo;
    }

    [StructLayout(LayoutKind.Sequential)]
    internal struct HARDWAREINPUT
    {
        internal uint uMsg;
        internal ushort wParamL, wParamH;
    }

    internal const uint INPUT_KEYBOARD = 1;
    internal const uint KEYEVENTF_KEYUP = 0x0002;
    internal const uint KEYEVENTF_EXTENDEDKEY = 0x0001;

    // Virtual key codes
    internal const ushort VK_CONTROL = 0x11;
    internal const ushort VK_SHIFT   = 0x10;
    internal const ushort VK_HOME    = 0x24;
    internal const ushort VK_END     = 0x23;
    internal const ushort VK_C       = 0x43;
    internal const ushort VK_V       = 0x56;
    internal const ushort VK_A       = 0x41;

    // ── Clipboard ────────────────────────────────────────────────────────────

    [DllImport("user32.dll")]
    internal static extern bool OpenClipboard(IntPtr hWndNewOwner);

    [DllImport("user32.dll")]
    internal static extern bool CloseClipboard();

    [DllImport("user32.dll")]
    internal static extern IntPtr GetForegroundWindow();

    [DllImport("user32.dll", CharSet = CharSet.Unicode)]
    internal static extern int GetWindowText(IntPtr hWnd, System.Text.StringBuilder text, int count);

    /// <summary>Returns the registered window-class name for the given window handle.</summary>
    [DllImport("user32.dll", CharSet = CharSet.Unicode, SetLastError = true)]
    internal static extern int GetClassName(IntPtr hWnd, System.Text.StringBuilder lpClassName, int nMaxCount);

    /// <summary>Returns the thread and process IDs that created the specified window.</summary>
    [DllImport("user32.dll", SetLastError = true)]
    internal static extern uint GetWindowThreadProcessId(IntPtr hWnd, out uint lpdwProcessId);

    /// <summary>
    /// Retrieves information about the active window or a specified GUI thread.
    /// Used to find <see cref="GUITHREADINFO.hwndFocus"/> — the child control that
    /// actually has keyboard focus inside the foreground window (e.g. the Scintilla
    /// control inside a Notepad++ top-level window).
    /// </summary>
    [DllImport("user32.dll", SetLastError = true)]
    internal static extern bool GetGUIThreadInfo(uint idThread, ref GUITHREADINFO lpgui);

    [System.Runtime.InteropServices.StructLayout(System.Runtime.InteropServices.LayoutKind.Sequential)]
    internal struct GUITHREADINFO
    {
        internal uint   cbSize;
        internal uint   flags;
        internal IntPtr hwndActive;
        /// <summary>The focused control within the active window's thread.</summary>
        internal IntPtr hwndFocus;
        internal IntPtr hwndCapture;
        internal IntPtr hwndMenuOwner;
        internal IntPtr hwndMoveSize;
        internal IntPtr hwndCaret;
        internal RECT   rcCaret;
    }

    [System.Runtime.InteropServices.StructLayout(System.Runtime.InteropServices.LayoutKind.Sequential)]
    internal struct RECT { internal int Left, Top, Right, Bottom; }

    /// <summary>
    /// Returns a serial number that is incremented each time the clipboard contents change.
    /// Use this to detect whether a Ctrl+C actually copied something new.
    /// Returns 0 if the calling thread does not have the clipboard open or
    /// another thread has changed the clipboard since the last call.
    /// </summary>
    [DllImport("user32.dll")]
    internal static extern uint GetClipboardSequenceNumber();

    [DllImport("user32.dll")]
    internal static extern bool EmptyClipboard();

    [DllImport("user32.dll")]
    internal static extern IntPtr GetClipboardData(uint uFormat);

    [DllImport("user32.dll")]
    internal static extern IntPtr SetClipboardData(uint uFormat, IntPtr hMem);

    [DllImport("kernel32.dll")]
    internal static extern IntPtr GlobalLock(IntPtr hMem);

    [DllImport("kernel32.dll")]
    [return: MarshalAs(UnmanagedType.Bool)]
    internal static extern bool GlobalUnlock(IntPtr hMem);

    [DllImport("kernel32.dll")]
    internal static extern IntPtr GlobalAlloc(uint uFlags, UIntPtr dwBytes);

    [DllImport("kernel32.dll")]
    internal static extern IntPtr GlobalFree(IntPtr hMem);

    internal const uint CF_UNICODETEXT = 13;
    internal const uint GMEM_MOVEABLE  = 0x0002;

    // ── SendMessage ───────────────────────────────────────────────────────────

    [DllImport("user32.dll", CharSet = CharSet.Auto)]
    internal static extern IntPtr SendMessage(IntPtr hWnd, uint Msg, IntPtr wParam, IntPtr lParam);

    // ── Scintilla API ─────────────────────────────────────────────────────────
    // These message IDs are stable across all Scintilla versions.
    // Used to query the editor's selection state without modifying it.

    /// <summary>Returns the position of the start of the selection (== end means no selection).</summary>
    internal const uint SCI_GETSELECTIONSTART = 2143;

    /// <summary>Returns the position of the end of the selection.</summary>
    internal const uint SCI_GETSELECTIONEND   = 2145;
}

using System.Runtime.InteropServices;

namespace Flipit.Infrastructure;

/// <summary>
/// All Win32 P/Invoke declarations in one place.
/// </summary>
internal static class NativeMethods
{
    // ── Hotkey ───────────────────────────────────────────────────────────────

    [DllImport("user32.dll", SetLastError = true)]
    [return: MarshalAs(UnmanagedType.Bool)]
    internal static extern bool RegisterHotKey(IntPtr hWnd, int id, uint fsModifiers, uint vk);

    [DllImport("user32.dll", SetLastError = true)]
    [return: MarshalAs(UnmanagedType.Bool)]
    internal static extern bool UnregisterHotKey(IntPtr hWnd, int id);

    // ── SendInput ────────────────────────────────────────────────────────────

    [DllImport("user32.dll", SetLastError = true)]
    internal static extern uint SendInput(uint nInputs, INPUT[] pInputs, int cbSize);

    [StructLayout(LayoutKind.Sequential)]
    internal struct INPUT
    {
        internal uint type;
        internal InputUnion U;
    }

    [StructLayout(LayoutKind.Explicit)]
    internal struct InputUnion
    {
        [FieldOffset(0)] internal MOUSEINPUT mi;
        [FieldOffset(0)] internal KEYBDINPUT ki;
        [FieldOffset(0)] internal HARDWAREINPUT hi;
    }

    [StructLayout(LayoutKind.Sequential)]
    internal struct KEYBDINPUT
    {
        internal ushort wVk;
        internal ushort wScan;
        internal uint dwFlags;
        internal uint time;
        internal IntPtr dwExtraInfo;
    }

    [StructLayout(LayoutKind.Sequential)]
    internal struct MOUSEINPUT
    {
        internal int dx, dy, mouseData;
        internal uint dwFlags, time;
        internal IntPtr dwExtraInfo;
    }

    [StructLayout(LayoutKind.Sequential)]
    internal struct HARDWAREINPUT
    {
        internal uint uMsg;
        internal ushort wParamL, wParamH;
    }

    internal const uint INPUT_KEYBOARD = 1;
    internal const uint KEYEVENTF_KEYUP = 0x0002;
    internal const uint KEYEVENTF_EXTENDEDKEY = 0x0001;

    // Virtual key codes
    internal const ushort VK_CONTROL = 0x11;
    internal const ushort VK_SHIFT   = 0x10;
    internal const ushort VK_HOME    = 0x24;
    internal const ushort VK_END     = 0x23;
    internal const ushort VK_C       = 0x43;
    internal const ushort VK_V       = 0x56;
    internal const ushort VK_A       = 0x41;

    // ── Clipboard ────────────────────────────────────────────────────────────

    [DllImport("user32.dll", SetLastError = true)]
    internal static extern bool OpenClipboard(IntPtr hWndNewOwner);

    [DllImport("user32.dll", SetLastError = true)]
    internal static extern bool CloseClipboard();

    [DllImport("user32.dll", SetLastError = true)]
    internal static extern IntPtr GetForegroundWindow();

    [DllImport("user32.dll", CharSet = CharSet.Unicode, SetLastError = true)]
    internal static extern int GetWindowText(IntPtr hWnd, System.Text.StringBuilder text, int count);

    /// <summary>Returns the registered window-class name for the given window handle.</summary>
    [DllImport("user32.dll", CharSet = CharSet.Unicode, SetLastError = true)]
    internal static extern int GetClassName(IntPtr hWnd, System.Text.StringBuilder lpClassName, int nMaxCount);

    /// <summary>Returns the thread and process IDs that created the specified window.</summary>
    [DllImport("user32.dll", SetLastError = true)]
    internal static extern uint GetWindowThreadProcessId(IntPtr hWnd, out uint lpdwProcessId);

    /// <summary>
    /// Retrieves information about the active window or a specified GUI thread.
    /// Used to find <see cref="GUITHREADINFO.hwndFocus"/> — the child control that
    /// actually has keyboard focus inside the foreground window (e.g. the Scintilla
    /// control inside a Notepad++ top-level window).
    /// </summary>
    [DllImport("user32.dll", SetLastError = true)]
    internal static extern bool GetGUIThreadInfo(uint idThread, ref GUITHREADINFO lpgui);

    [System.Runtime.InteropServices.StructLayout(System.Runtime.InteropServices.LayoutKind.Sequential)]
    internal struct GUITHREADINFO
    {
        internal uint   cbSize;
        internal uint   flags;
        internal IntPtr hwndActive;
        /// <summary>The focused control within the active window's thread.</summary>
        internal IntPtr hwndFocus;
        internal IntPtr hwndCapture;
        internal IntPtr hwndMenuOwner;
        internal IntPtr hwndMoveSize;
        internal IntPtr hwndCaret;
        internal RECT   rcCaret;
    }

    [System.Runtime.InteropServices.StructLayout(System.Runtime.InteropServices.LayoutKind.Sequential)]
    internal struct RECT { internal int Left, Top, Right, Bottom; }

    /// <summary>
    /// Returns a serial number that is incremented each time the clipboard contents change.
    /// Use this to detect whether a Ctrl+C actually copied something new.
    /// Returns 0 if the calling thread does not have the clipboard open or
    /// another thread has changed the clipboard since the last call.
    /// </summary>
    [DllImport("user32.dll")]
    internal static extern uint GetClipboardSequenceNumber();

    [DllImport("user32.dll", SetLastError = true)]
    internal static extern bool EmptyClipboard();

    [DllImport("user32.dll", SetLastError = true)]
    internal static extern IntPtr GetClipboardData(uint uFormat);

    [DllImport("user32.dll", SetLastError = true)]
    internal static extern IntPtr SetClipboardData(uint uFormat, IntPtr hMem);

    [DllImport("kernel32.dll", SetLastError = true)]
    internal static extern IntPtr GlobalLock(IntPtr hMem);

    [DllImport("kernel32.dll", SetLastError = true)]
    [return: MarshalAs(UnmanagedType.Bool)]
    internal static extern bool GlobalUnlock(IntPtr hMem);

    [DllImport("kernel32.dll", SetLastError = true)]
    internal static extern IntPtr GlobalAlloc(uint uFlags, UIntPtr dwBytes);

    [DllImport("kernel32.dll", SetLastError = true)]
    internal static extern IntPtr GlobalFree(IntPtr hMem);

    internal const uint CF_UNICODETEXT = 13;
    internal const uint GMEM_MOVEABLE  = 0x0002;

    // ── SendMessage ───────────────────────────────────────────────────────────

    [DllImport("user32.dll", CharSet = CharSet.Auto)]
    internal static extern IntPtr SendMessage(IntPtr hWnd, uint Msg, IntPtr wParam, IntPtr lParam);

    // ── Scintilla API ─────────────────────────────────────────────────────────
    // These message IDs are stable across all Scintilla versions.
    // Used to query the editor's selection state without modifying it.

    /// <summary>Returns the position of the start of the selection (== end means no selection).</summary>
    internal const uint SCI_GETSELECTIONSTART = 2143;

    /// <summary>Returns the position of the end of the selection.</summary>
    internal const uint SCI_GETSELECTIONEND   = 2145;
}

using Flipit.Core;

namespace Flipit.KeyboardEngine;

/// <summary>
/// Converts text between Hebrew and English based on physical keyboard layout mapping.
/// Stateless and thread-safe.
/// </summary>
public sealed class TextConverter : ITextConverter
{

    // Physical key position -> Hebrew character (Standard Hebrew keyboard layout)
    private static readonly Dictionary<char, char> EnglishToHebrew = new()
    {
        // Row 1 (numbers stay as-is)
        // Row 2 - QWERTY
        { 'q', '/' }, { 'Q', '/' },
        { 'w', '\'' }, { 'W', '\'' },
        { 'e', 'ק' }, { 'E', 'ק' },
        { 'r', 'ר' }, { 'R', 'ר' },
        { 't', 'א' }, { 'T', 'א' },
        { 'y', 'ט' }, { 'Y', 'ט' },
        { 'u', 'ו' }, { 'U', 'ו' },
        { 'i', 'ן' }, { 'I', 'ן' },
        { 'o', 'ם' }, { 'O', 'ם' },
        { 'p', 'פ' }, { 'P', 'פ' },
        // Row 3 - ASDF
        { 'a', 'ש' }, { 'A', 'ש' },
        { 's', 'ד' }, { 'S', 'ד' },
        { 'd', 'ג' }, { 'D', 'ג' },
        { 'f', 'כ' }, { 'F', 'כ' },
        { 'g', 'ע' }, { 'G', 'ע' },
        { 'h', 'י' }, { 'H', 'י' },
        { 'j', 'ח' }, { 'J', 'ח' },
        { 'k', 'ל' }, { 'K', 'ל' },
        { 'l', 'ך' }, { 'L', 'ך' },
        // Row 4 - ZXCV
        { 'z', 'ז' }, { 'Z', 'ז' },
        { 'x', 'ס' }, { 'X', 'ס' },
        { 'c', 'ב' }, { 'C', 'ב' },
        { 'v', 'ה' }, { 'V', 'ה' },
        { 'b', 'נ' }, { 'B', 'נ' },
        { 'n', 'מ' }, { 'N', 'מ' },
        { 'm', 'צ' }, { 'M', 'צ' },
        { ',', 'ת' },
        { '.', 'ץ' },
        { ';', 'ף' },
    };

    // Build reverse map: Hebrew -> English
    private static readonly Dictionary<char, char> HebrewToEnglish;

    // Chars that are uppercase Latin (used to detect shift for Hebrew->EN conversion)
    static TextConverter()
    {
        HebrewToEnglish = new Dictionary<char, char>();
        foreach (var kv in EnglishToHebrew)
        {
            // Only add lowercase english->hebrew mappings to build reverse
            // Hebrew chars map back to lowercase English
            if (!HebrewToEnglish.ContainsKey(kv.Value))
            {
                // Map to lowercase always since Hebrew has no case
                HebrewToEnglish[kv.Value] = char.ToLower(kv.Key);
            }
        }
    }

    public TextConverter() { }

    public string Convert(string text)
    {
        if (string.IsNullOrEmpty(text))
            return text;

        var direction = DetectDirection(text);

        return direction == ConversionDirection.HebrewToEnglish
            ? ConvertHebrewToEnglish(text)
            : ConvertEnglishToHebrew(text);
    }

    private static ConversionDirection DetectDirection(string text)
    {
        int hebrew = 0, english = 0;
        foreach (var c in text)
        {
            if (IsHebrew(c)) hebrew++;
            else if (char.IsLetter(c)) english++;
        }

        return hebrew >= english
            ? ConversionDirection.HebrewToEnglish
            : ConversionDirection.EnglishToHebrew;
    }

    private static string ConvertHebrewToEnglish(string text)
    {
        var sb = new System.Text.StringBuilder(text.Length);
        foreach (var c in text)
        {
            if (HebrewToEnglish.TryGetValue(c, out var mapped))
                sb.Append(mapped);
            else
                sb.Append(c); // preserve numbers, spaces, symbols
        }
        return sb.ToString();
    }

    private static string ConvertEnglishToHebrew(string text)
    {
        var sb = new System.Text.StringBuilder(text.Length);
        foreach (var c in text)
        {
            if (EnglishToHebrew.TryGetValue(c, out var mapped))
                sb.Append(mapped);
            else
                sb.Append(c); // preserve numbers, spaces, symbols
        }
        return sb.ToString();
    }

    private static bool IsHebrew(char c) => c >= '\u05D0' && c <= '\u05EA';
}

internal enum ConversionDirection { HebrewToEnglish, EnglishToHebrew }

using Flipit.Core;

namespace Flipit.KeyboardEngine;

/// <summary>
/// Converts text between Hebrew and English based on physical keyboard layout mapping.
/// Stateless and thread-safe.
/// </summary>
public sealed class TextConverter : ITextConverter
{

    // Physical key position -> Hebrew character (Standard Hebrew keyboard layout).
    // Lowercase-only keys: input is normalized via char.ToLower() before lookup
    // so there is no need to store both 'q' and 'Q'.
    private static readonly Dictionary<char, char> EnglishToHebrew = new()
    {
        // Row 2 - QWERTY
        { 'q', '/' },  { 'w', '\'' }, { 'e', 'ק' }, { 'r', 'ר' }, { 't', 'א' },
        { 'y', 'ט' },  { 'u', 'ו' },  { 'i', 'ן' }, { 'o', 'ם' }, { 'p', 'פ' },
        // Row 3 - ASDF
        { 'a', 'ש' },  { 's', 'ד' },  { 'd', 'ג' }, { 'f', 'כ' }, { 'g', 'ע' },
        { 'h', 'י' },  { 'j', 'ח' },  { 'k', 'ל' }, { 'l', 'ך' },
        // Row 4 - ZXCV
        { 'z', 'ז' },  { 'x', 'ס' },  { 'c', 'ב' }, { 'v', 'ה' }, { 'b', 'נ' },
        { 'n', 'מ' },  { 'm', 'צ' },
        // Punctuation
        { ',', 'ת' }, { '.', 'ץ' }, { ';', 'ף' },
    };

    // Build reverse map: Hebrew -> English
    private static readonly Dictionary<char, char> HebrewToEnglish;

    // Chars that are uppercase Latin (used to detect shift for Hebrew->EN conversion)
    static TextConverter()
    {
        HebrewToEnglish = new Dictionary<char, char>();
        foreach (var kv in EnglishToHebrew)
        {
            // Only add lowercase english->hebrew mappings to build reverse
            // Hebrew chars map back to lowercase English
            if (!HebrewToEnglish.ContainsKey(kv.Value))
            {
                // Map to lowercase always since Hebrew has no case
                HebrewToEnglish[kv.Value] = char.ToLower(kv.Key);
            }
        }
    }

    public TextConverter() { }

    public string Convert(string text)
    {
        if (string.IsNullOrEmpty(text))
            return text;

        var direction = DetectDirection(text);

        return direction == ConversionDirection.HebrewToEnglish
            ? ConvertHebrewToEnglish(text)
            : ConvertEnglishToHebrew(text);
    }

    private static ConversionDirection DetectDirection(string text)
    {
        int hebrew = 0, english = 0;
        foreach (var c in text)
        {
            if (IsHebrew(c)) hebrew++;
            else if (char.IsLetter(c)) english++;
        }

        return hebrew >= english
            ? ConversionDirection.HebrewToEnglish
            : ConversionDirection.EnglishToHebrew;
    }

    private static string ConvertHebrewToEnglish(string text)
    {
        var sb = new System.Text.StringBuilder(text.Length);
        foreach (var c in text)
        {
            if (HebrewToEnglish.TryGetValue(c, out var mapped))
                sb.Append(mapped);
            else
                sb.Append(c); // preserve numbers, spaces, symbols
        }
        return sb.ToString();
    }

    private static string ConvertEnglishToHebrew(string text)
    {
        var sb = new System.Text.StringBuilder(text.Length);
        foreach (var c in text)
        {
            // Normalize to lowercase — the dictionary contains only lowercase keys.
            // Both 'a' and 'A' map to the same Hebrew letter (Hebrew has no case).
            if (EnglishToHebrew.TryGetValue(char.ToLowerInvariant(c), out var mapped))
                sb.Append(mapped);
            else
                sb.Append(c); // preserve numbers, spaces, symbols
        }
        return sb.ToString();
    }

    private static bool IsHebrew(char c) => c >= '\u05D0' && c <= '\u05EA';
}

internal enum ConversionDirection { HebrewToEnglish, EnglishToHebrew }

using Flipit.Infrastructure;
using Flipit.Splash;
using Flipit.Tray;
using Microsoft.Extensions.DependencyInjection;

namespace Flipit;

internal static class Program
{
    [STAThread]
    static void Main()
    {
        // Prevent multiple instances
        using var mutex = new System.Threading.Mutex(true, "FlipitSingleInstance", out bool createdNew);
        if (!createdNew)
        {
            MessageBox.Show("Flipit is already running.", "Flipit",
                MessageBoxButtons.OK, MessageBoxIcon.Information);
            return;
        }

        Application.EnableVisualStyles();
        Application.SetCompatibleTextRenderingDefault(false);
        Application.SetHighDpiMode(HighDpiMode.SystemAware);

        var services = ServiceConfiguration.BuildServiceProvider();

        // Load settings on startup
        var settings = services.GetRequiredService<Flipit.Core.IAppSettings>();
        settings.Load();

        // Show the startup splash — it lives on the message loop and disposes itself
        using var splash = new StartupSplashForm();
        splash.Show();

        var context = services.GetRequiredService<TrayApplicationContext>();
        Application.Run(context);
    }
}

using Flipit.Infrastructure;
using Flipit.Splash;
using Flipit.Tray;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;

namespace Flipit;

internal static class Program
{
    [STAThread]
    static void Main()
    {
        // Prevent multiple instances
        using var mutex = new System.Threading.Mutex(true, "FlipitSingleInstance", out bool createdNew);
        if (!createdNew)
        {
            MessageBox.Show("Flipit is already running.", "Flipit",
                MessageBoxButtons.OK, MessageBoxIcon.Information);
            return;
        }

        Application.EnableVisualStyles();
        Application.SetCompatibleTextRenderingDefault(false);
        // PerMonitorV2 gives per-monitor crisp rendering on mixed-DPI setups (Win10 1703+)
        Application.SetHighDpiMode(HighDpiMode.PerMonitorV2);
        // Must be called BEFORE any control is created on this thread.
        // Creating the splash form below would otherwise make this call throw.
        Application.SetUnhandledExceptionMode(UnhandledExceptionMode.CatchException);

        // ── Show splash immediately ───────────────────────────────────────────
        // Shown BEFORE BuildServiceProvider() so it is visible during the heavy
        // DI / JIT startup work (especially slow on first run in single-file mode).
        // Application.DoEvents() flushes WM_PAINT so the OS renders the window.
        using var splash = new StartupSplashForm();
        splash.Show();
        Application.DoEvents();

        var services = ServiceConfiguration.BuildServiceProvider();
        var logger   = services.GetRequiredService<ILogger<object>>();

        // ── Global exception handlers ─────────────────────────────────────────
        Application.ThreadException += (_, e) =>
        {
            logger.LogError(e.Exception, "Unhandled UI thread exception");
            ShowFatalError(e.Exception.Message);
            Application.Exit();
        };

        AppDomain.CurrentDomain.UnhandledException += (_, e) =>
        {
            var ex = e.ExceptionObject as Exception;
            logger.LogError(ex, "Unhandled background thread exception: {Message}",
                ex?.Message ?? e.ExceptionObject?.ToString());
            // Cannot reliably show UI here — the runtime may be terminating.
        };

        // Load settings on startup
        var settings = services.GetRequiredService<Flipit.Core.IAppSettings>();
        settings.Load();

        var context = services.GetRequiredService<TrayApplicationContext>();
        Application.Run(context);
    }

    private static void ShowFatalError(string message)
    {
        try
        {
            MessageBox.Show(
                $"Flipit encountered an unexpected error and must close.\n\n{message}",
                "Flipit — Unexpected Error",
                MessageBoxButtons.OK,
                MessageBoxIcon.Error);
        }
        catch { /* cannot show UI — ignore */ }
    }
}

using Flipit.Core;

namespace Flipit.Tray;

/// <summary>
/// Invisible Win32 window whose sole purpose is receiving WM_HOTKEY messages.
/// </summary>
internal sealed class HiddenMessageWindow : NativeWindow
{
    private const int WM_HOTKEY = 0x0312;
    private readonly IHotkeyService _hotkeyService;

    public event EventHandler? HotkeyFired;

    public HiddenMessageWindow(IHotkeyService hotkeyService)
    {
        _hotkeyService = hotkeyService;

        // Create an invisible window to receive messages
        var cp = new CreateParams
        {
            Caption = "FlipitMessageWindow",
            Style = 0,
            ExStyle = 0,
            Parent = new IntPtr(-3) // HWND_MESSAGE
        };
        CreateHandle(cp);
    }

    protected override void WndProc(ref Message m)
    {
        if (m.Msg == WM_HOTKEY)
        {
            _hotkeyService.ProcessWmHotkey((int)m.WParam);
            HotkeyFired?.Invoke(this, EventArgs.Empty);
            return;
        }
        base.WndProc(ref m);
    }
}

using Flipit.Core;

namespace Flipit.Tray;

/// <summary>
/// Invisible Win32 window whose sole purpose is receiving WM_HOTKEY messages.
/// </summary>
internal sealed class HiddenMessageWindow : NativeWindow, IDisposable
{
    private const int WM_HOTKEY = 0x0312;
    /// <summary>
    /// Pseudo parent handle that creates a message-only window (not visible,
    /// not enumerable via EnumWindows). See MSDN "Message-Only Windows".
    /// </summary>
    private static readonly IntPtr HWND_MESSAGE = new(-3);
    private readonly IHotkeyService _hotkeyService;

    public event EventHandler? HotkeyFired;

    public HiddenMessageWindow(IHotkeyService hotkeyService)
    {
        _hotkeyService = hotkeyService;

        // Create an invisible window to receive messages
        var cp = new CreateParams
        {
            Caption = "FlipitMessageWindow",
            Style = 0,
            ExStyle = 0,
            Parent = HWND_MESSAGE
        };
        CreateHandle(cp);
    }

    protected override void WndProc(ref Message m)
    {
        if (m.Msg == WM_HOTKEY)
        {
            _hotkeyService.ProcessWmHotkey((int)m.WParam);
            HotkeyFired?.Invoke(this, EventArgs.Empty);
            return;
        }
        base.WndProc(ref m);
    }

    public void Dispose()
    {
        if (Handle != IntPtr.Zero)
            DestroyHandle();
    }
}

using Flipit.About;
using Flipit.Core;
using Flipit.Infrastructure;
using Flipit.Settings;
using Microsoft.Extensions.Logging;

namespace Flipit.Tray;

/// <summary>
/// Invisible background window. Hosts:
/// - System tray icon
/// - Global hotkey message pump
/// </summary>
public sealed class TrayApplicationContext : ApplicationContext
{
    private readonly IHotkeyService _hotkey;
    private readonly IFlipOrchestrator _orchestrator;
    private readonly IAppSettings _settings;
    private readonly ILogger<TrayApplicationContext> _logger;
    private readonly Func<SettingsForm> _settingsFormFactory;

    private NotifyIcon _trayIcon = null!;
    private HiddenMessageWindow _messageWindow = null!;
    private Icon? _appIcon;   // owned here; disposed in ExitApp / Dispose
    private AboutForm? _aboutForm;  // single-instance guard

    public TrayApplicationContext(
        IHotkeyService hotkey,
        IFlipOrchestrator orchestrator,
        IAppSettings settings,
        ILogger<TrayApplicationContext> logger,
        Func<SettingsForm> settingsFormFactory)
    {
        _hotkey = hotkey;
        _orchestrator = orchestrator;
        _settings = settings;
        _logger = logger;
        _settingsFormFactory = settingsFormFactory;

        Initialize();
    }

    private void Initialize()
    {
        // Hidden window for receiving WM_HOTKEY
        _messageWindow = new HiddenMessageWindow(_hotkey);

        // Register hotkey (handle must exist before calling Register)
        _hotkey.Register(_messageWindow.Handle);
        _hotkey.HotkeyPressed += OnHotkeyFired;

        // Tray icon — load once and hold a reference for proper disposal
        _appIcon = AppIcons.LoadAppIcon();
        _trayIcon = new NotifyIcon
        {
            Text = "Flipit",
            Icon = _appIcon,
            Visible = true,
            ContextMenuStrip = BuildMenu()
        };

        _trayIcon.DoubleClick += (_, _) => ShowSettings();

        _logger.LogInformation("Flipit started");
    }

    private void OnHotkeyFired(object? sender, EventArgs e)
    {
        _ = _orchestrator.FlipAsync();
    }

    private ContextMenuStrip BuildMenu()
    {
        var menu = new ContextMenuStrip();

        var enableItem = new ToolStripMenuItem("Enabled")
        {
            Checked = _settings.IsEnabled,
            CheckOnClick = true
        };
        enableItem.CheckedChanged += (_, _) =>
        {
            _settings.IsEnabled = enableItem.Checked;
            _settings.Save();
            _trayIcon.Text = _settings.IsEnabled ? "Flipit" : "Flipit (Disabled)";
        };

        menu.Items.Add(enableItem);
        menu.Items.Add(new ToolStripSeparator());
        menu.Items.Add("Settings",      null, (_, _) => ShowSettings());
        menu.Items.Add("About Flipit",  null, (_, _) => ShowAbout());
        menu.Items.Add(new ToolStripSeparator());
        menu.Items.Add("Exit",          null, (_, _) => ExitApp());

        return menu;
    }

    private void ShowSettings()
    {
        var form = _settingsFormFactory();
        form.FormClosed += (_, _) =>
        {
            // Refresh tray tooltip after settings change
            _trayIcon.Text = _settings.IsEnabled ? "Flipit" : "Flipit (Disabled)";
            UpdateMenuChecked();
        };
        form.ShowDialog();
    }

    private void ShowAbout()
    {
        if (_aboutForm is not null)
        {
            // Bring existing window to front
            if (_aboutForm.WindowState == FormWindowState.Minimized)
                _aboutForm.WindowState = FormWindowState.Normal;
            _aboutForm.Activate();
            return;
        }

        _aboutForm = new AboutForm();
        _aboutForm.FormClosed += (_, _) =>
        {
            _aboutForm?.Dispose();
            _aboutForm = null;
        };
        _aboutForm.Show();
    }

    private void UpdateMenuChecked()
    {
        if (_trayIcon.ContextMenuStrip?.Items[0] is ToolStripMenuItem item)
            item.Checked = _settings.IsEnabled;
    }

    private void ExitApp()
    {
        _hotkey.Unregister(_messageWindow.Handle);
        _trayIcon.Visible = false;
        _messageWindow.DestroyHandle();
        // Close the About window if open so it doesn't become orphaned
        _aboutForm?.Close();
        Application.Exit();
    }

    protected override void Dispose(bool disposing)
    {
        if (disposing)
        {
            _hotkey.Dispose();
            _trayIcon?.Dispose();
            _aboutForm?.Dispose();
            // Only dispose if it isn't a shared SystemIcons instance
            if (_appIcon is not null && !ReferenceEquals(_appIcon, SystemIcons.Application))
                _appIcon.Dispose();
        }
        base.Dispose(disposing);
    }
}

using Flipit.About;
using Flipit.Core;
using Flipit.Infrastructure;
using Flipit.Settings;
using Microsoft.Extensions.Logging;

namespace Flipit.Tray;

/// <summary>
/// Invisible background window.  Hosts:
///   • System tray icon with a polished ContextMenuStrip
///   • Global hotkey message pump
///
/// Menu appearance is driven by <see cref="TrayMenuRenderer"/> (custom
/// ProfessionalColorTable + targeted overrides) and <see cref="TrayMenuIcons"/>
/// (glyph-based icon bitmaps).  No third-party libraries or heavy owner-draw.
/// </summary>
public sealed class TrayApplicationContext : ApplicationContext
{
    private readonly IHotkeyService                  _hotkey;
    private readonly IFlipOrchestrator               _orchestrator;
    private readonly IAppSettings                    _settings;
    private readonly ILogger<TrayApplicationContext> _logger;
    private readonly Func<SettingsForm>              _settingsFormFactory;

    // ── Tray infrastructure ───────────────────────────────────────────────────
    private NotifyIcon          _trayIcon      = null!;
    private HiddenMessageWindow _messageWindow = null!;
    private Icon?               _appIcon;

    // ── Menu GDI resources ────────────────────────────────────────────────────
    private TrayMenuRenderer?  _renderer;
    private Bitmap?            _iconEnabledOn;   // checkmark — shown only when enabled
    private Bitmap?            _iconSettings;
    private Bitmap?            _iconAbout;
    private Bitmap?            _iconExit;

    // ── Menu item ref ─────────────────────────────────────────────────────────
    private ToolStripMenuItem? _enableItem;

    // ── Single-instance About window ─────────────────────────────────────────
    private AboutForm? _aboutForm;

    // ── Constructor ───────────────────────────────────────────────────────────

    public TrayApplicationContext(
        IHotkeyService                  hotkey,
        IFlipOrchestrator               orchestrator,
        IAppSettings                    settings,
        ILogger<TrayApplicationContext> logger,
        Func<SettingsForm>              settingsFormFactory)
    {
        _hotkey              = hotkey;
        _orchestrator        = orchestrator;
        _settings            = settings;
        _logger              = logger;
        _settingsFormFactory = settingsFormFactory;

        Initialize();
    }

    // ── Initialization ────────────────────────────────────────────────────────

    private void Initialize()
    {
        _messageWindow = new HiddenMessageWindow(_hotkey);
        _appIcon       = AppIcons.LoadAppIcon();

        _trayIcon = new NotifyIcon
        {
            Text             = TrayTooltip(),
            Icon             = _appIcon,
            ContextMenuStrip = BuildMenu(),
            Visible          = true,
        };
        _trayIcon.DoubleClick += (_, _) => ShowSettings();

        bool registered = _hotkey.Register(_messageWindow.Handle);
        _hotkey.HotkeyPressed += OnHotkeyFired;

        if (!registered)
        {
            _trayIcon.ShowBalloonTip(
                5000,
                "Flipit \u2014 Hotkey Not Registered",
                $"Could not register {_settings.Hotkey.DisplayText}. " +
                "Another application may be using it. " +
                "Open Settings to choose a different hotkey.",
                ToolTipIcon.Warning);
        }

        _logger.LogInformation("Flipit started");
    }

    // ── Menu construction ─────────────────────────────────────────────────────

    private ContextMenuStrip BuildMenu()
    {
        int iconSz      = SystemInformation.SmallIconSize.Width;
        _iconEnabledOn  = TrayMenuIcons.EnabledOn(iconSz);   // checkmark bitmap
        _iconSettings   = TrayMenuIcons.Settings(iconSz);
        _iconAbout      = TrayMenuIcons.About(iconSz);
        _iconExit       = TrayMenuIcons.Exit(iconSz);

        _renderer = new TrayMenuRenderer();

        var menu = new ContextMenuStrip
        {
            Renderer         = _renderer,
            Font             = new Font("Segoe UI", 9f, FontStyle.Regular, GraphicsUnit.Point),
            ImageScalingSize = new Size(iconSz, iconSz),
            Padding          = new Padding(0, 3, 0, 3),
            ShowImageMargin  = true,
            ShowCheckMargin  = false,
        };

        // ── Enabled toggle ────────────────────────────────────────────────────
        // Checkmark icon appears only when enabled; null = no image when disabled.
        _enableItem = new ToolStripMenuItem
        {
            Name         = "enableItem",
            Text         = "Enabled",
            Image        = _settings.IsEnabled ? _iconEnabledOn : null,
            Checked      = _settings.IsEnabled,
            CheckOnClick = true,
        };
        _enableItem.CheckedChanged += OnEnabledChanged;
        menu.Items.Add(_enableItem);

        // ── Settings ──────────────────────────────────────────────────────────
        menu.Items.Add(new ToolStripMenuItem("Settings", _iconSettings,
            (_, _) => ShowSettings()));

        // ── About ─────────────────────────────────────────────────────────────
        menu.Items.Add(new ToolStripMenuItem("About Flipit", _iconAbout,
            (_, _) => ShowAbout()));

        // ── Single separator before Exit ──────────────────────────────────────
        menu.Items.Add(new ToolStripSeparator());

        // ── Exit ──────────────────────────────────────────────────────────────
        menu.Items.Add(new ToolStripMenuItem("Exit", _iconExit,
            (_, _) => ExitApp()));

        return menu;
    }

    // ── Event handlers ────────────────────────────────────────────────────────

    private void OnHotkeyFired(object? sender, EventArgs e)
    {
        _ = _orchestrator.FlipAsync().ContinueWith(t =>
        {
            if (t.IsFaulted)
                _logger.LogError(t.Exception, "Flip task faulted");
        }, TaskScheduler.Default);
    }

    private void OnEnabledChanged(object? sender, EventArgs e)
    {
        if (_enableItem is null) return;

        _settings.IsEnabled = _enableItem.Checked;
        _settings.Save();

        // Show checkmark only when enabled; no image when disabled
        _enableItem.Image  = _settings.IsEnabled ? _iconEnabledOn : null;
        _trayIcon.Text     = TrayTooltip();
    }

    // ── Settings / About windows ──────────────────────────────────────────────

    private void ShowSettings()
    {
        using var form = _settingsFormFactory();
        form.FormClosed += (_, _) =>
        {
            _trayIcon.Text = TrayTooltip();
            SyncEnabledItem();
        };
        form.ShowDialog();
    }

    private void ShowAbout()
    {
        if (_aboutForm is not null)
        {
            if (_aboutForm.WindowState == FormWindowState.Minimized)
                _aboutForm.WindowState = FormWindowState.Normal;
            _aboutForm.Activate();
            return;
        }

        _aboutForm = new AboutForm();
        _aboutForm.FormClosed += (_, _) =>
        {
            _aboutForm?.Dispose();
            _aboutForm = null;
        };
        _aboutForm.Show();
    }

    // ── Shutdown ──────────────────────────────────────────────────────────────

    private void ExitApp()
    {
        _hotkey.Unregister(_messageWindow.Handle);
        _trayIcon.Visible = false;
        _messageWindow.DestroyHandle();
        _messageWindow.Dispose();
        _aboutForm?.Close();
        Application.Exit();
    }

    // ── Helpers ───────────────────────────────────────────────────────────────

    private string TrayTooltip() =>
        _settings.IsEnabled ? "Flipit" : "Flipit (Disabled)";

    private void SyncEnabledItem()
    {
        if (_enableItem is null) return;
        _enableItem.Checked = _settings.IsEnabled;
        _enableItem.Image   = _settings.IsEnabled ? _iconEnabledOn : null;
    }

    // ── Disposal ──────────────────────────────────────────────────────────────

    protected override void Dispose(bool disposing)
    {
        if (disposing)
        {
            _hotkey.Dispose();
            _trayIcon?.Dispose();
            _messageWindow?.Dispose();
            _aboutForm?.Dispose();
            _renderer?.Dispose();

            _iconEnabledOn?.Dispose();
            _iconSettings?.Dispose();
            _iconAbout?.Dispose();
            _iconExit?.Dispose();

            if (_appIcon is not null && !ReferenceEquals(_appIcon, SystemIcons.Application))
                _appIcon.Dispose();
        }
        base.Dispose(disposing);
    }
}

using System.Drawing.Drawing2D;
using System.Drawing.Text;

namespace Flipit.Tray;

/// <summary>
/// Generates the small icon bitmaps used in the tray context menu.
///
/// Strategy (highest quality first):
///   1. Segoe MDL2 Assets   — ships with Windows 10/11; crisp vector glyphs.
///   2. Segoe UI Symbol      — ships with Windows 7+; common Unicode symbols.
///   3. Hand-drawn GDI+      — always available; simple geometric fallbacks.
///
/// All bitmaps are 32-bpp ARGB with a transparent background so they render
/// cleanly against any menu background colour.
///
/// Callers are responsible for disposing every bitmap returned.
/// </summary>
internal static class TrayMenuIcons
{
    // ── Segoe MDL2 Assets PUA code points ────────────────────────────────────
    // These are the same glyphs used by Windows shell, PowerToys, Settings, etc.
    private const string GlyphCheckmark = "\uE73E"; // CheckMark
    private const string GlyphSettings  = "\uE713"; // Gear / Settings
    private const string GlyphInfo      = "\uE946"; // Information circle
    private const string GlyphClose     = "\uE711"; // Cancel / X

    // ── Segoe UI Symbol Unicode fallbacks ────────────────────────────────────
    private const string FbCheckmark    = "\u2713"; // ✓  CHECK MARK
    private const string FbSettings     = "\u2699"; // ⚙  GEAR
    private const string FbInfo         = "\u2139"; // ℹ  INFORMATION SOURCE
    private const string FbClose        = "\u2715"; // ✕  MULTIPLICATION X

    // ── Singleton font availability cache ────────────────────────────────────
    private static readonly bool _hasMdl2    = FontFamilyExists("Segoe MDL2 Assets");
    private static readonly bool _hasSymbol  = FontFamilyExists("Segoe UI Symbol");

    // ── Public factory methods ────────────────────────────────────────────────

    /// <summary>Checkmark icon — shown on the Enabled item only when the app is active.</summary>
    public static Bitmap EnabledOn(int size)  => GlyphBitmap(GlyphCheckmark, FbCheckmark, Color.FromArgb(72, 72, 72), size);

    /// <summary>Gear icon for "Settings".</summary>
    public static Bitmap Settings(int size)   => GlyphBitmap(GlyphSettings, FbSettings, Color.FromArgb(72, 72, 72), size);

    /// <summary>Info circle for "About".</summary>
    public static Bitmap About(int size)      => GlyphBitmap(GlyphInfo, FbInfo,         Color.FromArgb(72, 72, 72), size);

    /// <summary>X icon for "Exit".</summary>
    public static Bitmap Exit(int size)       => GlyphBitmap(GlyphClose, FbClose,       Color.FromArgb(72, 72, 72), size);

    // ── Private helpers ───────────────────────────────────────────────────────
    /// Tries Segoe MDL2 Assets first, then Segoe UI Symbol, then a hand-drawn shape.
    /// </summary>
    private static Bitmap GlyphBitmap(string mdl2Glyph, string symbolFallback,
                                       Color color, int size)
    {
        string glyph;
        string fontFamily;

        if (_hasMdl2)
        {
            glyph      = mdl2Glyph;
            fontFamily = "Segoe MDL2 Assets";
        }
        else if (_hasSymbol)
        {
            glyph      = symbolFallback;
            fontFamily = "Segoe UI Symbol";
        }
        else
        {
            // No suitable symbol font — fall back to a simple drawn shape
            return FallbackGlyph(symbolFallback, size, color);
        }

        var bmp = NewBitmap(size);
        using var g = Graphics.FromImage(bmp);
        g.TextRenderingHint = TextRenderingHint.AntiAliasGridFit;

        // Scale font so the glyph fills roughly 75 % of the bitmap height
        float em = size * 0.72f;
        using var font  = new Font(fontFamily, em, FontStyle.Regular, GraphicsUnit.Pixel);
        using var brush = new SolidBrush(color);

        var textSz = g.MeasureString(glyph, font);
        float x = (size - textSz.Width)  / 2f;
        float y = (size - textSz.Height) / 2f;
        g.DrawString(glyph, font, brush, x, y);
        return bmp;
    }

    /// <summary>
    /// Plain GDI+ fallback when no symbol font is available.
    /// Renders the Unicode character using Segoe UI (always present on Vista+).
    /// </summary>
    private static Bitmap FallbackGlyph(string text, int size, Color color)
    {
        var bmp = NewBitmap(size);
        using var g = Graphics.FromImage(bmp);
        g.TextRenderingHint = TextRenderingHint.AntiAliasGridFit;

        float em = size * 0.65f;
        using var font  = new Font("Segoe UI", em, FontStyle.Regular, GraphicsUnit.Pixel);
        using var brush = new SolidBrush(color);

        var sz = g.MeasureString(text, font);
        g.DrawString(text, font, brush,
            (size - sz.Width)  / 2f,
            (size - sz.Height) / 2f);
        return bmp;
    }

    private static Bitmap NewBitmap(int size)
    {
        var bmp = new Bitmap(size, size, System.Drawing.Imaging.PixelFormat.Format32bppArgb);
        using var g = Graphics.FromImage(bmp);
        g.Clear(Color.Transparent);
        return bmp;
    }

    private static bool FontFamilyExists(string name)
    {
        try
        {
            using var ff = new FontFamily(name);
            return true;
        }
        catch
        {
            return false;
        }
    }
}

using System.Drawing.Drawing2D;

namespace Flipit.Tray;

// ── Color table ───────────────────────────────────────────────────────────────

/// <summary>
/// ProfessionalColorTable that replaces the default Windows XP–era gradients
/// with a clean, flat palette inspired by Windows 11 context menus.
///
/// Key choices:
///   • Pure-white background removes the vintage gray stripe.
///   • Single flat hover colour (no gradient) keeps the look modern.
///   • Image-margin background matches the menu background so the icon column
///     blends in seamlessly — just like PowerToys / EarTrumpet.
///   • Border is a very soft gray so the popup looks floated, not boxed.
/// </summary>
internal sealed class FlipitColorTable : ProfessionalColorTable
{
    // ── Named palette entries ─────────────────────────────────────────────────

    internal static readonly Color MenuBg         = Color.White;
    internal static readonly Color HoverBg        = Color.FromArgb(229, 229, 229);
    internal static readonly Color PressedBg      = Color.FromArgb(210, 210, 210);
    internal static readonly Color BorderColor     = Color.FromArgb(200, 200, 200);
    internal static readonly Color SepColor        = Color.FromArgb(218, 218, 218);
    internal static readonly Color HeaderBg        = Color.FromArgb(246, 246, 246);
    internal static readonly Color TextPrimary     = Color.FromArgb(28,  28,  28);
    internal static readonly Color TextSecondary   = Color.FromArgb(120, 120, 120);

    // ── ProfessionalColorTable overrides ──────────────────────────────────────

    // Menu surface
    public override Color ToolStripDropDownBackground        => MenuBg;
    public override Color MenuBorder                         => BorderColor;
    public override Color MenuItemBorder                     => Color.Transparent;   // no per-item border ring

    // Hover / pressed states — flat (begin == end == middle)
    public override Color MenuItemSelected                   => HoverBg;
    public override Color MenuItemSelectedGradientBegin      => HoverBg;
    public override Color MenuItemSelectedGradientEnd        => HoverBg;
    public override Color MenuItemPressedGradientBegin       => PressedBg;
    public override Color MenuItemPressedGradientEnd         => PressedBg;
    public override Color MenuItemPressedGradientMiddle      => PressedBg;

    // Image / check margin — match the menu background so no gray stripe appears
    public override Color ImageMarginGradientBegin           => MenuBg;
    public override Color ImageMarginGradientEnd             => MenuBg;
    public override Color ImageMarginGradientMiddle          => MenuBg;
    public override Color ImageMarginRevealedGradientBegin   => MenuBg;
    public override Color ImageMarginRevealedGradientEnd     => MenuBg;
    public override Color ImageMarginRevealedGradientMiddle  => MenuBg;

    // Check-mark background
    public override Color CheckBackground                    => HoverBg;
    public override Color CheckSelectedBackground            => HoverBg;
    public override Color CheckPressedBackground             => PressedBg;

    // Toolbar / menu-bar (not used in a tray app, but keeps everything consistent)
    public override Color MenuStripGradientBegin             => MenuBg;
    public override Color MenuStripGradientEnd               => MenuBg;
    public override Color ToolStripGradientBegin             => MenuBg;
    public override Color ToolStripGradientEnd               => MenuBg;
    public override Color ToolStripGradientMiddle            => MenuBg;
    public override Color ToolStripBorder                    => BorderColor;
    public override Color SeparatorDark                      => SepColor;
    public override Color SeparatorLight                     => MenuBg;
}

// ── Renderer ─────────────────────────────────────────────────────────────────

/// <summary>
/// Lightweight custom renderer for the Flipit tray context menu.
///
/// Builds on <see cref="ToolStripProfessionalRenderer"/> (no full owner-draw)
/// and adds only the targeted overrides needed to achieve a clean, modern look:
///
///   • Flat white background — no gradients, no XP chrome.
///   • Rounded-rectangle hover highlight (4 px corner radius).
///   • Hairline separator rendered with consistent horizontal padding.
///   • Image-margin background suppressed so icons sit against pure white.
///   • Check mark replaced by a simple tick character to stay consistent with
///     the icon style (no Windows 95-era groove square).
///
/// DPI notes:
///   All pixel values that affect visual weight (padding, radius, separator
///   thickness) are intentionally kept in logical units.  WinForms scales
///   the ContextMenuStrip via <see cref="ToolStrip.ImageScalingSize"/> and
///   the system DPI; we piggyback on that instead of doing our own scaling.
/// </summary>
internal sealed class TrayMenuRenderer : ToolStripProfessionalRenderer, IDisposable
{
    public TrayMenuRenderer() : base(new FlipitColorTable()) { }
    // ── Background ────────────────────────────────────────────────────────────

    protected override void OnRenderToolStripBackground(ToolStripRenderEventArgs e)
    {
        // Flat white — no gradient, no etched edge.
        e.Graphics.Clear(FlipitColorTable.MenuBg);
    }

    // ── Image margin ──────────────────────────────────────────────────────────

    protected override void OnRenderImageMargin(ToolStripRenderEventArgs e)
    {
        // Paint the image column the same colour as the menu background so it
        // is invisible — icons appear to float against a pure-white surface.
        using var brush = new SolidBrush(FlipitColorTable.MenuBg);
        e.Graphics.FillRectangle(brush, e.AffectedBounds);
    }

    // ── Hover / pressed item background ──────────────────────────────────────

    protected override void OnRenderMenuItemBackground(ToolStripItemRenderEventArgs e)
    {
        var item = e.Item;

        // Non-interactive items (header, disabled) receive no highlight.
        if (!item.Enabled || !item.Selected && !item.Pressed)
            return;

        // Rounded rectangle — 4 px radius gives a Windows-11 feel without
        // looking overdone.  We deflate by (2, 1) to leave a 2 px left/right
        // gap and 1 px top/bottom gap from the item edge.
        var bounds = Rectangle.Inflate(new Rectangle(Point.Empty, item.Size), -2, -1);
        var color  = item.Pressed ? FlipitColorTable.PressedBg : FlipitColorTable.HoverBg;

        e.Graphics.SmoothingMode = SmoothingMode.AntiAlias;
        using var brush = new SolidBrush(color);
        using var path  = RoundedRect(bounds, 4);
        e.Graphics.FillPath(brush, path);
        e.Graphics.SmoothingMode = SmoothingMode.Default;
    }

    // ── Separator ─────────────────────────────────────────────────────────────

    protected override void OnRenderSeparator(ToolStripSeparatorRenderEventArgs e)
    {
        // Hairline centered in the separator item height, with horizontal inset.
        var r  = e.Item.ContentRectangle;
        int y  = r.Top + r.Height / 2;
        int x1 = r.Left  + 2;
        int x2 = r.Right - 2;

        using var pen = new Pen(FlipitColorTable.SepColor);
        e.Graphics.DrawLine(pen, x1, y, x2, y);
    }

    // ── Check mark ────────────────────────────────────────────────────────────

    protected override void OnRenderItemCheck(ToolStripItemImageRenderEventArgs e)
    {
        // The Enabled menu item uses an explicit Image that already reflects
        // the checked/unchecked state (green dot / gray dot).  We suppress
        // the default "check box" so it does not double-render.
        // For any other item that happens to have CheckState set, we fall back
        // to the professional renderer's built-in behaviour.
        if (e.Item.Image is not null)
            return;

        base.OnRenderItemCheck(e);
    }

    // ── Disposal ──────────────────────────────────────────────────────────────

    public void Dispose()
    {
        // ToolStripRenderer / ToolStripProfessionalRenderer do not implement
        // IDisposable, so there is nothing to forward to.
        GC.SuppressFinalize(this);
    }

    // ── Helpers ───────────────────────────────────────────────────────────────

    private static GraphicsPath RoundedRect(Rectangle r, int radius)
    {
        int d    = radius * 2;
        var path = new GraphicsPath();
        path.AddArc(r.Left,          r.Top,           d, d, 180, 90);
        path.AddArc(r.Right - d,     r.Top,           d, d, 270, 90);
        path.AddArc(r.Right - d,     r.Bottom - d,    d, d,   0, 90);
        path.AddArc(r.Left,          r.Bottom - d,    d, d,  90, 90);
        path.CloseFigure();
        return path;
    }
}
